#include <stdio.h>

// AND gate function
int AND(int a, int b) {
    return (a && b);
}

// OR gate function
int OR(int a, int b) {
    return (a || b);
}

// NOT gate function
int NOT(int a) {
    return (!a);
}

int main() {
    printf("AND Gate Truth Table:\n");
    printf("A B | A AND B\n");
    printf("--------------\n");
    for(int a=0; a<=1; a++) {
        for(int b=0; b<=1; b++) {
            printf("%d %d |    %d\n", a, b, AND(a,b));
        }
    }

    printf("\nOR Gate Truth Table:\n");
    printf("A B | A OR B\n");
    printf("-------------\n");
    for(int a=0; a<=1; a++) {
        for(int b=0; b<=1; b++) {
            printf("%d %d |    %d\n", a, b, OR(a,b));
        }
    }

    printf("\nNOT Gate Truth Table:\n");
    printf("A | NOT A\n");
    printf("-------\n");
    for(int a=0; a<=1; a++) {
        printf("%d |   %d\n", a, NOT(a));
    }
    return 0;
}

public class HalfAdder {
    // XOR gate implementation for Sum
    public static int sum(int A, int B) {
        return (A ^ B);  // XOR operation
    }

    // AND gate implementation for Carry
    public static int carry(int A, int B) {
        return (A & B);  // AND operation
    }

    public static void main(String[] args) {
        System.out.println("Half Adder Truth Table:");
        System.out.println("A B | Sum Carry");
        System.out.println("-----------");

        for (int A = 0; A <= 1; A++) {
            for (int B = 0; B <= 1; B++) {
                int sumBit = sum(A, B);
                int carryBit = carry(A, B);
                System.out.println(A + " " + B + " |  " + sumBit + "    " + carryBit);
            }
        }

        // Example: Add 1 + 1
        System.out.println("\nExample: Adding 1 + 1");
        System.out.println("Sum: " + sum(1,1) + ", Carry: " + carry(1,1));
        System.out.println("Result: 1 + 1 = 10 in binary");
    }
}
